const allPosts = $input.all()[0]?.json?.data || [];
const targetUrl = $('Configure Post & Message').first()?.json?.postUrl;
const post = allPosts.find(p => p.permalink === targetUrl);
if (!post) throw new Error('Post URL not found in recent media.');
return { json: post };

const comments = $("Get All Comments").first().json.data || [];
const contacted = $input.all().map(i => String(i.json.comment_id || '').trim());
const newOnes = comments.filter(c => !contacted.includes(String(c.id).trim()));

if (newOnes.length === 0) return [{ json: { noNewComments: true } }];
return newOnes.map(c => ({ json: { 
  commentId: c.id,
  comment: c.text,
  username: c.username, 
  timestamp: c.timestamp, 
  postUrl: $('Configure Post & Message').first().json.postUrl
}}));

const loopItems = $('Loop Over Items').all();
const processed = loopItems ? loopItems.length : 0;
return [{ json: {
  message: 'Monitoring cycle complete.',
  commentsProcessed: processed,
  timestamp: new Date().toISOString()
} }];

const items = $input.item.json;
const text = items.content?.parts?.[0]?.text || items.text || '';
const cleanJson = text.replace(/```json|```/g, "").trim();
try {
  const response = JSON.parse(cleanJson);
  return { json: response };
} catch(e) {
  return { json: { reply: '', parseError: true, rawText: text } };
}

